import React, { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import "./AdminDashboard.css";

const AdminDashboard = () => {
  const navigate = useNavigate();

  const [products, setProducts] = useState([]);
  const [users, setUsers] = useState([]);
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(false);
  const [activePage, setActivePage] = useState("");

  /* ================= LOGOUT ================= */
  const logout = () => {
    localStorage.removeItem("adminToken");
    navigate("/admin/login");
  };

  /* ================= FETCH DATA ================= */
  const fetchProducts = async () => {
    setActivePage("products");
    setLoading(true);
    try {
      const res = await axios.get("http://localhost:5000/api/admin/products");
      setProducts(res.data);
    } catch {
      setProducts([]);
    }
    setLoading(false);
  };

  const fetchUsers = async () => {
    setActivePage("users");
    setLoading(true);
    try {
      const res = await axios.get("http://localhost:5000/api/admin/users");
      setUsers(res.data);
    } catch {
      setUsers([]);
    }
    setLoading(false);
  };

  const fetchOrders = async () => {
    setActivePage("orders");
    setLoading(true);
    try {
      const res = await axios.get("http://localhost:5000/api/admin/orders");
      setOrders(res.data);
    } catch {
      setOrders([]);
    }
    setLoading(false);
  };

  /* ================= PRODUCT CRUD ================= */
  const [newProduct, setNewProduct] = useState({
    name: "",
    price: "",
    stock: 50,
    image_url: "",
    category: "",
  });

  const handleChange = (e) => {
    setNewProduct({ ...newProduct, [e.target.name]: e.target.value });
  };

  const addProduct = async (e) => {
    e.preventDefault();
    try {
      await axios.post("http://localhost:5000/api/admin/products", newProduct);
      alert("Product added successfully");
      setNewProduct({
        name: "",
        price: "",
        stock: 50,
        image_url: "",
        category: "",
      });
      fetchProducts();
    } catch {
      alert("Failed to add product");
    }
  };

  const deleteProduct = async (id) => {
    if (!window.confirm("Delete this product?")) return;
    await axios.delete(`http://localhost:5000/api/admin/products/${id}`);
    fetchProducts();
  };

  const updateProduct = async (id, oldName) => {
    const name = prompt("New product name:", oldName);
    if (!name) return;
    await axios.put(`http://localhost:5000/api/admin/products/${id}`, { name });
    fetchProducts();
  };

  /* ================= PAGES ================= */
  const ProductsPage = () => {
    if (loading) return <p>Loading products...</p>;
    if (!products.length) return <p>No products found.</p>;

    return (
      <>
        <h2 className="page-title">Products</h2>

        <form className="product-form" onSubmit={addProduct}>
          <input name="name" placeholder="Product Name" value={newProduct.name} onChange={handleChange} required />
          <input type="number" name="price" placeholder="Price" value={newProduct.price} onChange={handleChange} required />
          <input type="number" name="stock" placeholder="Stock" value={newProduct.stock} onChange={handleChange} />
          <input name="category" placeholder="Category" value={newProduct.category} onChange={handleChange} />
          <input name="image_url" placeholder="Image URL" value={newProduct.image_url} onChange={handleChange} />
          <button className="btn-primary">Add Product</button>
        </form>

        <table className="admin-table">
          <thead>
            <tr>
              <th>ID</th><th>Name</th><th>Price</th><th>Stock</th><th>Category</th><th>Image</th><th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {products.map((p) => (
              <tr key={p.id}>
                <td>{p.id}</td>
                <td>{p.name}</td>
                <td>RM {p.price}</td>
                <td>{p.stock}</td>
                <td>{p.category}</td>
                <td>
                  {p.image_url && <img src={p.image_url} alt={p.name} width="45" />}
                </td>
                <td>
                  <button className="btn-edit" onClick={() => updateProduct(p.id, p.name)}>Edit</button>
                  <button className="btn-delete" onClick={() => deleteProduct(p.id)}>Delete</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </>
    );
  };

  const UsersPage = () => (
    <>
      <h2 className="page-title">Users</h2>
      <table className="admin-table">
        <thead>
          <tr><th>ID</th><th>Name</th><th>Email</th></tr>
        </thead>
        <tbody>
          {users.map((u) => (
            <tr key={u.id}>
              <td>{u.id}</td>
              <td>{u.full_name}</td>
              <td>{u.email}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </>
  );

  const OrdersPage = () => (
    <>
      <h2 className="page-title">Orders</h2>
      <table className="admin-table">
        <thead>
          <tr><th>ID</th><th>Name</th><th>Email</th><th>Total</th><th>Status</th></tr>
        </thead>
        <tbody>
          {orders.map((o) => (
            <tr key={o.id}>
              <td>{o.id}</td>
              <td>{o.full_name}</td>
              <td>{o.email}</td>
              <td>RM {o.total_amount}</td>
              <td>{o.payment_status}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </>
  );

  /* ================= LAYOUT ================= */
  return (
    <div className="admin-layout">
      <aside className="admin-sidebar">
        <h2 className="logo">ShopAdmin</h2>
        <button className="nav-link" onClick={fetchProducts}>Products</button>
        <button className="nav-link" onClick={fetchOrders}>Orders</button>
        <button className="nav-link" onClick={fetchUsers}>Users</button>
        <button className="logout-btn" onClick={logout}>Logout</button>
      </aside>

      <main className="admin-content">
        {!activePage && <p>Welcome to Admin Dashboard</p>}
        {activePage === "products" && <ProductsPage />}
        {activePage === "users" && <UsersPage />}
        {activePage === "orders" && <OrdersPage />}
      </main>
    </div>
  );
};

export default AdminDashboard;
